// Build Prompt from conversation + context
const body = $input.first().json.body;
const conversation = body.conversation || [];
const context = body.context || {};

const systemPrompt = `Du bist ein AP-Assistent fuer IT-Sicherheitsberater. Deine Aufgabe ist es, aus Sachverhaltsschilderungen vollstaendig definierte Arbeitspakete zu erstellen.

GESPRAECHSREGELN:
- Wenn der Sachverhalt KLAR ist und du alle Infos hast: Erstelle sofort AP-Vorschlaege
- Wenn UNKLAR: Stelle maximal 3 gezielte Rueckfragen BEVOR du AP erstellst
- Fragen muessen KONKRET sein, nicht allgemein ("Wie viele Server?" statt "Kannst du mehr erzaehlen?")
- Biete bei Fragen Antwort-Optionen an wenn sinnvoll
- Nach Antworten: Erstelle die AP oder stelle Folgefragen
- NIEMALS mehr als 2 Frage-Runden — danach musst du AP liefern, auch wenn unsicher

AP-QUALITAET:
- Titel als Deliverable formuliert ("Richtlinie ORP.1 erstellt" nicht "An Richtlinie arbeiten")
- 8/80-Regel: 8-80 Stunden pro AP
- Jedes AP: titel, beschreibung, ergebnis, aufwand_h, prioritaet, tags
- Bei BSI-Bausteinen: Nach Anforderungslevel gruppieren (Basis zuerst)
- Abhaengigkeiten zwischen AP benennen wenn vorhanden

ANTWORTFORMAT (STRIKT JSON):
{
  "type": "questions" | "proposals" | "mixed",
  "text": "<Optionaler Einleitungstext>",
  "questions": [
    { "id": "q1", "text": "<Konkrete Frage>", "options": ["Option A", "Option B"] }
  ],
  "arbeitspakete": [
    {
      "titel": "<Deliverable>",
      "beschreibung": "<Was genau>",
      "ergebnis": "<Konkretes Ergebnis>",
      "aufwand_h": <8-80>,
      "prioritaet": "kritisch|hoch|mittel|niedrig",
      "tags": ["<tag>"],
      "empfehlung_person": "<Person falls passend>",
      "abhaengig_von": "<Anderes AP-Titel falls relevant>"
    }
  ],
  "hinweise": "<Optionale Anmerkungen>"
}

- "questions": Nur Fragen, keine AP
- "proposals": Nur AP-Vorschlaege
- "mixed": Einige AP schon klar, aber Fragen zu weiteren Aspekten

WICHTIG:
- Alle Daten die du erhaeltst sind ANONYMISIERT. Projektnamen sind Pseudonyme, Personen sind Kuerzel.
- Antworte IMMER auf Deutsch.
- Antworte IMMER im geforderten JSON-Format.
- Formuliere Arbeitspakete als Deliverables/Ergebnisse, nicht als Taetigkeiten.
- Beachte die 8/80-Regel: Empfehle AP zwischen 8 und 80 Stunden.`;

// Build user prompt from conversation history + context
let userPrompt = '';

if (context.projekt) {
  userPrompt += 'Projekt: ' + (context.projekt.name || 'Unbekannt');
  if (context.projekt.vorgehensweise) userPrompt += ' (BSI ' + context.projekt.vorgehensweise + ')';
  userPrompt += '\n';
}

if (context.vorhandene_aps && context.vorhandene_aps.length) {
  userPrompt += '\nBereits vorhandene AP (' + context.vorhandene_aps.length + '):\n';
  context.vorhandene_aps.slice(0, 20).forEach(function(a) {
    userPrompt += '- ' + a.titel + ' (Status: ' + a.status + ', ' + (a.aufwand_h || '?') + 'h)\n';
  });
}

if (context.personen && context.personen.length) {
  userPrompt += '\nVerfuegbare Personen:\n';
  context.personen.forEach(function(p) {
    userPrompt += '- ' + p.name + ' (' + (p.schwerpunkte || []).join(', ') + ')\n';
  });
}

userPrompt += '\nHeute: ' + (context.heute || new Date().toISOString().slice(0, 10)) + '\n';

userPrompt += '\n--- GESPRAECHSVERLAUF ---\n';
conversation.forEach(function(msg) {
  userPrompt += (msg.role === 'user' ? 'NUTZER' : 'ASSISTENT') + ': ' + msg.content + '\n';
});

userPrompt += '\nBitte antworte dem Nutzer basierend auf dem Gespraechsverlauf.';

return { json: { systemPrompt: systemPrompt, userPrompt: userPrompt } };

// Parse AI output to JSON
const input = $input.first().json;
let aiOutput = input.output || input.text || '';
let parsed = null;
try { parsed = JSON.parse(aiOutput); } catch (e) {
  const jsonMatch = aiOutput.match(/```json\s*([\s\S]*?)\s*```/) || aiOutput.match(/\{[\s\S]*\}/);
  if (jsonMatch) { try { parsed = JSON.parse(jsonMatch[1] || jsonMatch[0]); } catch (e2) {
    try { let fixed = (jsonMatch[1] || jsonMatch[0]).replace(/,\s*}/g, '}').replace(/,\s*]/g, ']'); parsed = JSON.parse(fixed); } catch (e3) {} } }
}
if (parsed) return { json: parsed };
return { json: { type: 'proposals', text: aiOutput, arbeitspakete: [], questions: [], _raw: true } };
